function fmtVal(v) {
	if (v === null) return "null";
	if (v === undefined) return "undefined";
	if (typeof v === "string") return JSON.stringify(v).slice(0, 80);
	return String(v);
}

function lift(id, bc, instrs) {
	const C = bc.constants;
	const out = [];
	const meta = [
		bc.isAsync && "async",
		bc.isGen && "generator",
		bc.isArrow && "arrow",
		bc.isStrict && "strict",
	].filter(Boolean);

	out.push("=".repeat(72));
	out.push(`FUNCTION  ${id}   [${meta.join(", ") || "normal"}]`);
	out.push(
		`  params=${bc.pCount}  locals=${bc.rCount}  constants=${C.length}  instrs=${instrs.length}`
	);
	out.push("");
	out.push("  -- Constant Pool --");
	C.forEach((v, i) =>
		out.push(`    C[${String(i).padStart(3)}] = ${fmtVal(v)}`)
	);
	out.push("");
	out.push("  -- Instructions --");

	for (const { pos, op, arg } of instrs) {
		const name = (OP[op] || `UNKNOWN_${op}`).padEnd(20);
		let detail = "";
		switch (op) {
			case 26:
				detail = `C[${arg}] = ${fmtVal(C[arg])}`;
				break;
			case 80:
				detail = `.${C[arg]}`;
				break;
			case 270:
				detail = `.${C[arg]} = <tos>`;
				break;
			case 251:
				detail = `"${C[arg]}"`;
				break;
			case 206:
				detail = `"${C[arg]}" = <tos>`;
				break;
			case 45:
				detail = `declare "${C[arg]}"`;
				break;
			case 69:
				detail = `typeof "${C[arg]}"`;
				break;
			case 91:
				detail = `"${C[arg]}"++`;
				break;
			case 79:
				detail = `-> func ${C[arg]}`;
				break;
			case 192: {
				const nm = C[arg & 0xffff],
					st = (arg >> 16) & 1;
				detail = `"${nm}" static=${st}`;
				break;
			}
			case 167: {
				const r = arg & 0xffff,
					ni = (arg >>> 16) & 0xffff;
				detail = `reg[${r}].${C[ni]}`;
				break;
			}
			case 299: {
				const ra = arg & 0xffff,
					rb = (arg >>> 16) & 0xffff;
				detail = `reg[${ra}] < reg[${rb}]`;
				break;
			}
			case 252: {
				const ra = arg & 0xffff,
					rb = (arg >>> 16) & 0xffff;
				detail = `reg[${ra}] === reg[${rb}]`;
				break;
			}
			case 179: {
				const ct = (arg >> 16) & 0xffff,
					fn = arg & 0xffff;
				detail = `catch->[${ct === 0xffff ? "none" : ct}] finally->[${
					fn === 0xffff ? "none" : fn
				}]`;
				break;
			}
			case 267:
			case 70:
			case 154:
			case 269:
				detail = `-> [${arg}]`;
				break;
			case 277:
			case 157:
				detail = `argc=${Math.abs(arg)} spread=${arg < 0}`;
				break;
			case 118:
				detail = `argc=${arg}`;
				break;
			case 24:
			case 160:
			case 281:
			case 225:
				detail = `local[${arg}]`;
				break;
			case 162:
				detail = `param[${arg}]`;
				break;
			case 173:
			case 116:
			case 98:
			case 38:
				detail = `reg[${arg}]`;
				break;
			default:
				if (arg !== 0) detail = `arg=${arg}`;
		}
		out.push(`    [${String(pos).padStart(4, "0")}] ${name} ${detail}`);
	}

	out.push("");
	return out.join("\n");
}

function main() {
	if (Object.keys(_c72lg3).length === 0) {
		console.error(
			"Paste your _c72lg3 payload into the slot at the top of this file, then re-run."
		);
		process.exit(1);
	}

	const key = computeKey();
	console.log(`RC4 key (_pwf): ${key}\n`);

	const sections = [];
	for (const [id, raw] of Object.entries(_c72lg3)) {
		try {
			const bc = parseBytecode(rc4(b64ToBytes(raw), key));
			const instrs = descramble(bc);
			sections.push(lift(id, bc, instrs));
		} catch (e) {
			sections.push(`ERROR decoding ${id}: ${e.message}\n`);
		}
	}

	const output = sections.join("\n");
	require("fs").writeFileSync("deobfuscated.txt", output, "utf8");
	console.log(output);
	console.log("\nAlso written to deobfuscated.txt");
}

main();
